import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { getElectionByConstituency, updateElection } from "../../api/electionsApi";

function ElectionDashboard() {
  const { id } = useParams();
  const [election, setElection] = useState(null);
  const [form, setForm] = useState({});

  useEffect(() => {
    getElectionByConstituency(id).then(res => setElection(res.data));
  }, [id]);

  const save = async () => {
    await updateElection(election.id, form);
    alert("Election updated");
  };

  if (!election) return <p>No election created</p>;

  return (
    <div>
      <h2>Election Management</h2>
      <p>Status: {election.status}</p>

      <input
        type="datetime-local"
        onChange={e => setForm({ ...form, application_deadline: e.target.value })}
        placeholder="Application Deadline"
      />

      <input
        type="datetime-local"
        onChange={e => setForm({ ...form, voter_registration_deadline: e.target.value })}
        placeholder="Voter Registration Deadline"
      />

      <input
        type="datetime-local"
        onChange={e => setForm({ ...form, start_time: e.target.value })}
        placeholder="Election Start"
      />

      <input
        type="datetime-local"
        onChange={e => setForm({ ...form, end_time: e.target.value })}
        placeholder="Election End"
      />

      <button onClick={save}>Save</button>
    </div>
  );
}

export default ElectionDashboard;
